// ─── FCM / Push Notification Helper ──────────────────────────────────────────
// Real device push is live: registers firebase-messaging-sw.js, calls
// getMessaging()/getToken({vapidKey}), and saves the real FCM token via
// /api/save-token. Falls back to a mock token only when VITE_FIREBASE_* env
// vars aren't configured on this deploy (in-app notifications still work via
// backstage_notif_inbox regardless — see deliverNotification() below).
// ─────────────────────────────────────────────────────────────────────────────
async function requestNotificationPermission(userId) {
  if (!("Notification" in window) || !("serviceWorker" in navigator)) return null;
  const permission = await Notification.requestPermission();
  if (permission !== "granted") return null;

  const FB_API_KEY    = import.meta.env.VITE_FIREBASE_API_KEY;
  const FB_PROJECT_ID = import.meta.env.VITE_FIREBASE_PROJECT_ID;
  const FB_VAPID      = import.meta.env.VITE_FIREBASE_VAPID_KEY;

  if (FB_API_KEY && FB_PROJECT_ID && FB_VAPID) {
    try {
      const { initializeApp, getApps } = await import('firebase/app');
      const { getMessaging, getToken }  = await import('firebase/messaging');
      const config = {
        apiKey:            FB_API_KEY,
        authDomain:        import.meta.env.VITE_FIREBASE_AUTH_DOMAIN,
        projectId:         FB_PROJECT_ID,
        messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
        appId:             import.meta.env.VITE_FIREBASE_APP_ID,
      };
      const firebaseApp = getApps().length ? getApps()[0] : initializeApp(config);
      const messaging   = getMessaging(firebaseApp);
      const reg = await navigator.serviceWorker.register('/firebase-messaging-sw.js');
      // Send config to SW so it can handle background messages
      const sw = reg.active || reg.waiting || reg.installing;
      if (sw) sw.postMessage({ type: 'FIREBASE_CONFIG', config });
      await navigator.serviceWorker.ready;
      const token = await getToken(messaging, { vapidKey: FB_VAPID, serviceWorkerRegistration: reg });
      if (token) {
        await api.post('/api/save-token', { token, userId, platform: 'web' });
        return token;
      }
    } catch (err) {
      console.warn('[FCM] getToken failed:', err?.message);
    }
  }

  // Fallback: mock token (in-app notifications still work, no real device push)
  const mockToken = `mock-fcm-${userId}-${Date.now()}`;
  await api.post('/api/save-token', { token: mockToken, userId }).catch(()=>{});
  return mockToken;
}

// ─── NOTIFICATION DELIVERY HELPER ────────────────────────────────────────────
// Coordinates all delivery channels for a single notification event.
//
// params:
//   notif       — { id?, type, icon, title, body, color, targetModal?, targetTab? }
//   pushEnabled — user's app-level push preference (notifSettings.phonePush)
//   emailBackup — user's email backup preference (notifSettings.emailBackup)
//   priority    — 'low' | 'normal' | 'high' | 'critical'
//
// Channel rules:
//   in_app  — always written to localStorage inbox
//   push    — attempted if pushEnabled AND browser permission === 'granted'
//   email   — attempted if push is unavailable AND priority >= high AND emailBackup
async function deliverNotification({ notif, pushEnabled = false, emailBackup = true, priority = 'normal' }) {
  // 1. In-app (always) — store createdAt, not a frozen "Just now" string, so the
  // Notification Center can render an accurate relative time on every render.
  const entry = { ...notif, id: notif.id || `n-${Date.now()}`, read: false, createdAt: notif.createdAt || new Date().toISOString() };
  const inbox = ls.get('backstage_notif_inbox', []);
  ls.set('backstage_notif_inbox', [entry, ...inbox].slice(0, 50));

  const browserGranted = window.Notification?.permission === 'granted';

  // 2. Push (best-effort, fire-and-forget)
  if (pushEnabled && browserGranted) {
    api.post('/api/send-notification', {
      title: notif.title,
      body:  notif.body,
      data:  { targetModal: notif.targetModal || '', targetTab: notif.targetTab || '' },
    }).catch(() => {});
  }

  // 3. Email backup for high/critical when push is unavailable
  const pushUnavailable = !pushEnabled || !browserGranted || window.Notification?.permission === 'denied';
  const isHighPriority  = priority === 'high' || priority === 'critical';
  if (pushUnavailable && isHighPriority && emailBackup) {
    api.post('/api/notifications/email-backup', {
      title:    notif.title,
      body:     notif.body,
      priority,
    }).catch(() => {});
  }
}

// Reads delivery preferences from localStorage for the given user.
// Call at notification-fire time, not on mount, so prefs are always current.
function getDeliveryPrefs(user) {
  const key = user?.id || user?.email || "anon";
  const s = ls.get(`backstage_notification_settings_${key}`, DEFAULT_NOTIF_SETTINGS);
  const pushEnabled = s.phonePush === true
    && ls.get(`backstage_push_enabled_${key}`, false) === true
    && window.Notification?.permission === 'granted';
  return { pushEnabled, emailBackup: s.emailBackup !== false };
}

