// ─── ADMIN MODERATION QUEUE ──────────────────────────────────────────────────
// Minimal triage UI for moderation_reports. Admin-gated server-side (requireAdmin)
// — this screen is only reachable if /api/admin/check returned isAdmin:true.
// Action buttons (warn/suspend/ban/remove) are PLACEHOLDERS: they write an
// audit-log row to moderation_actions and update the report's status/action_taken.
// They do NOT suspend accounts, ban users, or delete content — that enforcement
// layer is intentionally deferred (needs appeals + reversibility + notifications).
const STATUS_BADGE = {
  pending:       { label:"Pending",       color: "#f5a623" },
  reviewed:      { label:"Reviewed",      color: "#5ac8fa" },
  dismissed:     { label:"Dismissed",     color: "#8e8e93" },
  action_taken:  { label:"Action Taken",  color: "#ff5c7a" },
};

function ModerationReportCard({ report, onUpdate, onAction }) {
  const [notes, setNotes] = useState(report.resolution_notes || "");
  const [savingNotes, setSavingNotes] = useState(false);
  const [showActions, setShowActions] = useState(false);
  const [busy, setBusy] = useState(false);
  const badge = STATUS_BADGE[report.status] || STATUS_BADGE.pending;

  const run = async (fn) => { setBusy(true); try { await fn(); } finally { setBusy(false); } };

  return (
    <div style={{ background:C.surface, border:`1.5px solid ${C.border}`, borderRadius:14, padding:14, marginBottom:10 }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:8, gap:8 }}>
        <div>
          <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:13 }}>
            {report.type?.toUpperCase()} · {report.reason}
          </p>
          <p style={{ fontSize:10.5, color:C.textMid, marginTop:2 }}>
            {new Date(report.created_at).toLocaleString()}
          </p>
        </div>
        <span style={{ background:`${badge.color}1c`, border:`1px solid ${badge.color}55`, color:badge.color, borderRadius:99, padding:"3px 9px", fontSize:10, fontWeight:700, flexShrink:0 }}>{badge.label}</span>
      </div>

      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8, marginBottom:8 }}>
        <div style={{ background:C.surfaceHi, borderRadius:10, padding:"8px 10px" }}>
          <p style={{ fontSize:9.5, color:C.textDim, fontWeight:700, marginBottom:2 }}>REPORTER</p>
          <p style={{ fontSize:11.5 }}>{report.reporter?.username ? `@${report.reporter.username}` : (report.reporter?.email || report.reporter_id || "—")}</p>
        </div>
        <div style={{ background:C.surfaceHi, borderRadius:10, padding:"8px 10px" }}>
          <p style={{ fontSize:9.5, color:C.textDim, fontWeight:700, marginBottom:2 }}>TARGET</p>
          <p style={{ fontSize:11.5 }}>{report.target_handle ? `@${report.target_handle}` : (report.target_id || "—")}</p>
        </div>
      </div>

      {report.detail && (
        <div style={{ background:C.surfaceHi, borderRadius:10, padding:"8px 10px", marginBottom:8 }}>
          <p style={{ fontSize:9.5, color:C.textDim, fontWeight:700, marginBottom:2 }}>DETAILS</p>
          <p style={{ fontSize:11.5, lineHeight:1.5, color:C.textMid }}>{report.detail}</p>
        </div>
      )}

      {report.action_taken && (
        <p style={{ fontSize:10.5, color:C.textMid, marginBottom:8 }}>
          Last action: <strong>{report.action_taken.replace(/_/g," ")}</strong>
          {report.reviewer?.username ? ` by @${report.reviewer.username}` : ""}
          {report.reviewed_at ? ` · ${new Date(report.reviewed_at).toLocaleDateString()}` : ""}
        </p>
      )}

      <textarea
        value={notes}
        onChange={e=>setNotes(e.target.value)}
        placeholder="Resolution notes (internal only)..."
        style={{ width:"100%", minHeight:50, background:C.surfaceHi, border:`1.5px solid ${C.border}`, borderRadius:10, padding:"8px 10px", color:C.text, fontSize:11.5, fontFamily:"inherit", resize:"vertical", boxSizing:"border-box", marginBottom:8 }}
      />

      <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
        <button disabled={busy} onClick={()=>run(()=>onUpdate(report.id, { status:"reviewed", resolution_notes: notes }))}
          style={{ background:"none", border:`1.5px solid ${C.border}`, borderRadius:9, padding:"6px 11px", color:C.textMid, fontSize:10.5, fontWeight:700, cursor:"pointer" }}>Mark Reviewed</button>
        <button disabled={busy} onClick={()=>run(()=>onUpdate(report.id, { status:"dismissed", resolution_notes: notes }))}
          style={{ background:"none", border:`1.5px solid ${C.border}`, borderRadius:9, padding:"6px 11px", color:C.textMid, fontSize:10.5, fontWeight:700, cursor:"pointer" }}>Dismiss</button>
        <button disabled={busy} onClick={()=>run(()=>onUpdate(report.id, { resolution_notes: notes }, ()=>setSavingNotes(false)))}
          style={{ background:"none", border:`1.5px solid ${C.border}`, borderRadius:9, padding:"6px 11px", color:C.textMid, fontSize:10.5, fontWeight:700, cursor:"pointer" }}>{savingNotes ? "Saving..." : "Save Notes"}</button>
        <button disabled={busy} onClick={()=>setShowActions(s=>!s)}
          style={{ background:`${C.rose}14`, border:`1.5px solid ${C.rose}55`, borderRadius:9, padding:"6px 11px", color:C.rose, fontSize:10.5, fontWeight:700, cursor:"pointer" }}>Action Taken ▾</button>
      </div>

      {showActions && (
        <div style={{ marginTop:8, padding:10, background:C.surfaceHi, borderRadius:10, border:`1px solid ${C.border}` }}>
          <p style={{ fontSize:9.5, color:C.textDim, marginBottom:7, lineHeight:1.5 }}>
            ⚠️ Placeholder actions — these log a decision for audit purposes only. They do not suspend, ban, or delete anything yet.
          </p>
          <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
            {[
              ["warn_user","Warn User"],
              ["suspend_user","Suspend (placeholder)"],
              ["ban_user","Ban (placeholder)"],
              ["remove_content","Remove Content (placeholder)"],
            ].map(([type,label])=>(
              <button key={type} disabled={busy} onClick={()=>run(async ()=>{ await onAction(report.id, type, notes); setShowActions(false); })}
                style={{ background:"none", border:`1.5px solid ${C.border}`, borderRadius:9, padding:"6px 11px", color:C.textMid, fontSize:10, fontWeight:700, cursor:"pointer" }}>{label}</button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

function ModerationQueue({ onBack }) {
  const [reports, setReports] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);
  const [filter, setFilter] = useState("pending");

  const load = async () => {
    setLoading(true); setError(false);
    const res = await api.get(`/api/admin/moderation/reports${filter ? `?status=${filter}` : ""}`);
    if (res?.reports) setReports(res.reports); else setError(true);
    setLoading(false);
  };
  useEffect(()=>{ load(); }, [filter]); // eslint-disable-line react-hooks/exhaustive-deps

  const updateReport = async (id, patch) => {
    const res = await api.patch(`/api/admin/moderation/reports/${id}`, patch);
    if (res?.report) setReports(rs => rs.map(r => r.id === id ? { ...r, ...res.report } : r));
  };
  const actionOnReport = async (id, action_type, notes) => {
    const res = await api.post(`/api/admin/moderation/reports/${id}/action`, { action_type, notes });
    if (res?.logged) await load();
  };

  return (
    <div style={{ height:"100%", display:"flex", flexDirection:"column", overflow:"hidden" }}>
      <div style={{ padding:"16px 20px", display:"flex", gap:10, alignItems:"center", flexShrink:0 }}>
        <button onClick={onBack} style={{ background:"none", border:"none", color:C.textMid, fontSize:22, cursor:"pointer" }}>←</button>
        <h2 style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:19 }}>Moderation Queue 🛡️</h2>
      </div>
      <Screen style={{ padding:"0 20px calc(120px + env(safe-area-inset-bottom))" }}>
        <div style={{ display:"flex", gap:6, marginBottom:14, flexWrap:"wrap" }}>
          {[["pending","Pending"],["reviewed","Reviewed"],["dismissed","Dismissed"],["action_taken","Actioned"],["","All"]].map(([val,label])=>(
            <button key={label} onClick={()=>setFilter(val)}
              style={{ background: filter===val ? `${C.accent}1c` : "none", border:`1.5px solid ${filter===val?C.accent:C.border}`, borderRadius:99, padding:"6px 13px", color: filter===val ? C.accent : C.textMid, fontSize:11, fontWeight:700, cursor:"pointer" }}>{label}</button>
          ))}
        </div>

        {loading ? (
          <p style={{ fontSize:12, color:C.textMid, textAlign:"center", padding:30 }}>Loading reports...</p>
        ) : error ? (
          <Empty emoji="⚠️" title="Couldn't load reports" sub="Check your connection and try again." />
        ) : reports.length === 0 ? (
          <Empty emoji="🛡️" title="No reports here" sub="Nothing in this queue right now." />
        ) : reports.map(r => (
          <ModerationReportCard key={r.id} report={r} onUpdate={updateReport} onAction={actionOnReport} />
        ))}
      </Screen>
    </div>
  );
}

// ─── 19. EVENT DISCOVERY ─────────────────────────────────────────────────────
function EventDiscovery({ onBack, go }) {
  const [query, setQuery] = useState("");
  const [city, setCity] = useState("Dallas");
  const [results, setResults] = useState(MOCK_CONCERTS);
  const [loading, setLoading] = useState(false);
  const [saved, setSaved] = useState({});
  const [going, setGoing] = useState({});
  const search = async () => { setLoading(true); await new Promise(r=>setTimeout(r,700)); setResults(MOCK_CONCERTS.filter(c=>(!query||c.name.toLowerCase().includes(query.toLowerCase())||c.group.toLowerCase().includes(query.toLowerCase()))&&(!city||c.city.toLowerCase().includes(city.toLowerCase())))||MOCK_CONCERTS); setLoading(false); };
  return (
    <div style={{ height:"100%", display:"flex", flexDirection:"column", overflow:"hidden" }}>
      <div style={{ padding:"16px 20px",display:"flex",gap:10,alignItems:"center",flexShrink:0 }}>
        <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <h2 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:19 }}>Find Concerts 🎤</h2>
      </div>
      <Screen style={{ padding:"0 20px calc(120px + env(safe-area-inset-bottom))" }}>
        <div style={{ display:"flex",gap:8,marginBottom:10 }}>
          <input value={query} onChange={e=>setQuery(e.target.value)} onKeyDown={e=>e.key==="Enter"&&search()} placeholder="Group or tour..." style={{ flex:1,padding:"10px 13px",borderRadius:11,background:C.surfaceHi,border:`1.5px solid ${C.border}`,color:C.text,fontSize:12.5 }} />
          <input value={city} onChange={e=>setCity(e.target.value)} placeholder="City" style={{ width:90,padding:"10px 12px",borderRadius:11,background:C.surfaceHi,border:`1.5px solid ${C.border}`,color:C.text,fontSize:12.5 }} />
          <button onClick={search} style={{ background:C.accent,border:"none",borderRadius:11,padding:"0 14px",color:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11,cursor:"pointer" }}>{loading?"...":"Go"}</button>
        </div>
        <div style={{ background:`${C.gold}08`,border:`1px solid ${C.gold}22`,borderRadius:11,padding:"8px 13px",marginBottom:14 }}>
          <p style={{ fontSize:11,color:C.textMid }}>🎫 Concert search — connect backend events API to show live shows.</p>
        </div>
        {results.map(c=>(
          <Card key={c.id} color={c.color} glow style={{ marginBottom:12 }}>
            <Pill color={c.color} active small>{c.group}</Pill>
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:16,marginTop:8,marginBottom:4 }}>{c.name}</p>
            <p style={{ fontSize:11.5,color:C.textMid,marginBottom:12 }}>📍 {c.city} · 📅 {c.date}</p>
            <div style={{ display:"flex",gap:8 }}>
              <button onClick={()=>setGoing(g=>({...g,[c.id]:!g[c.id]}))} style={{ flex:1,padding:"9px",borderRadius:11,background:going[c.id]?`${C.mint}22`:c.color,border:going[c.id]?`1.5px solid ${C.mint}`:"none",color:going[c.id]?C.mint:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11,cursor:"pointer" }}>{going[c.id]?"✓ Going":"I'm Going"}</button>
              <button onClick={()=>setSaved(s=>({...s,[c.id]:!s[c.id]}))} style={{ padding:"9px 13px",borderRadius:11,background:"transparent",border:`1.5px solid ${saved[c.id]?C.gold:C.border}`,color:saved[c.id]?C.gold:C.textMid,fontSize:13,cursor:"pointer" }}>{saved[c.id]?"★":"☆"}</button>
              <button onClick={()=>go("concertprep")} style={{ flex:1,padding:"9px",borderRadius:11,background:"transparent",border:`1.5px solid ${c.color}44`,color:c.color,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11,cursor:"pointer" }}>Prep →</button>
            </div>
          </Card>
        ))}
      </Screen>
    </div>
  );
}

// ─── 20. CONCERT DAY MODE ────────────────────────────────────────────────────
// ─── CONCERT LIFECYCLE HELPERS ───────────────────────────────────────────────
// Returns: 'future' | 'upcoming' | 'soon' | 'today' | 'afterglow' | 'expired' | 'no_date'
// Callers gate their UI on this — never render fake countdowns.
function parseConcertShowTime(dateISO, showTime) {
  if (!dateISO) return new Date(NaN);
  try {
    const t = (showTime || '20:00').trim();
    // Try direct parse first ("2026-05-23 8:00 PM" works in Chrome but not Safari)
    const direct = new Date(`${dateISO}T${t}`);
    if (!isNaN(direct.getTime())) return direct;
    // Parse "8:00 PM" / "7:30 PM" / "20:00" manually
    const m = t.match(/(\d+):(\d+)\s*(AM|PM)?/i);
    if (!m) return new Date(`${dateISO}T20:00:00`);
    let h = parseInt(m[1], 10);
    const min = parseInt(m[2], 10);
    const period = (m[3] || '').toUpperCase();
    if (period === 'PM' && h !== 12) h += 12;
    if (period === 'AM' && h === 12) h = 0;
    return new Date(`${dateISO}T${h.toString().padStart(2,'0')}:${min.toString().padStart(2,'0')}:00`);
  } catch { return new Date(NaN); }
}

function getConcertStatus(concert) {
  if (!concert) return 'no_date';
  const startISO = concert.startDateISO;
  const endISO   = concert.endDateISO || startISO;
  if (!startISO) return 'no_date';

  const now      = Date.now();
  const showEnd  = parseConcertShowTime(endISO,   concert.showEndTime || '23:00');
  const showStart= parseConcertShowTime(startISO,  concert.showTime   || '20:00');
  if (isNaN(showEnd.getTime()) || isNaN(showStart.getTime())) return 'no_date';

  const msAfterEnd  = now - showEnd.getTime();
  const msToStart   = showStart.getTime() - now;
  const HOUR = 3600_000;

  if (msAfterEnd  > 72 * HOUR) return 'expired';   // >72 h after last night → hide
  if (msAfterEnd  >  0       ) return 'afterglow';  // 0–72 h post-show
  if (msToStart   <= 0       ) return 'today';      // show in progress
  if (msToStart   <= 24*HOUR ) return 'soon';       // <24 h to first night
  if (msToStart   <= 7*24*HOUR) return 'upcoming';  // 1–7 days out
  return 'future';                                  // >7 days → no Home banner
}
// ─── CONCERT DAY UTILS ────────────────────────────────────────────────────────
function useConcertCountdown(showTime, concertDate) {
  const [timeLeft, setTimeLeft] = useState("");
  useEffect(()=>{
    const tick = ()=>{
      // Parse concert date + show time into a real Date for accurate countdown
      // Format: concert.date = "Apr 30, 2026", showTime = "7:30 PM"
      let target = null;
      try {
        const dateStr = concertDate || "Apr 30, 2026";
        const timeStr = showTime || "7:30 PM";
        const combined = `${dateStr} ${timeStr}`;
        target = new Date(combined);
        if(isNaN(target.getTime())) throw new Error("Invalid date");
      } catch {
        // Unparseable date — show nothing rather than a fake countdown
        setTimeLeft(""); return;
      }
      const diff = target - Date.now();
      // If the target is in the past, the banner shouldn't be visible (getConcertStatus gates it)
      if(diff <= 0) { setTimeLeft("Show time! 🎤"); return; }
      const h = Math.floor(diff/3600000);
      const m = Math.floor((diff%3600000)/60000);
      const s = Math.floor((diff%60000)/1000);
      setTimeLeft(`${h}h ${m}m ${s}s`);
    };
    tick(); const t = setInterval(tick,1000); return ()=>clearInterval(t);
  },[showTime, concertDate]);
  return timeLeft;
}

// ─── VENUE CROWD-SOURCED TIPS ─────────────────────────────────────────────────
// TODO: GET /api/venues/:concertId/tips — fan-submitted tips with helpful votes
// TODO: POST /api/venues/:concertId/tips — submit a new tip
function VenueCrowdTips({ concertId, concertColor }) {
  const KEY = `backstage_venue_tips_${concertId}`;
  const [tips, setTips]       = useState(()=>ls.get(KEY, MOCK_VENUE_TIPS_DEFAULT));
  const [catFilter, setCatFilter] = useState("all");
  const [submitting, setSubmitting] = useState(false);
  const [draft, setDraft]     = useState({ text:"", category:"merch" });
  const [helpfulVoted, setHelpfulVoted] = useState({});

  useEffect(()=>{ ls.set(KEY, tips); }, [tips]);

  const CAT_LABELS = { all:"All", merch:"👕 Merch", parking:"🚗 Parking", gates:"🚪 Gates", food:"🍔 Food", other:"💡 Other" };
  const col = concertColor || C.pink;

  const filtered = catFilter==="all" ? tips : tips.filter(t=>t.category===catFilter);

  const submitTip = () => {
    if(!draft.text.trim()) return;
    const newTip = { id:`vt-${Date.now()}`, category:draft.category, text:draft.text, helpful:0, reported:false, author:"@you", time:"just now" };
    setTips([newTip,...tips]);
    ls.set(KEY,[newTip,...tips]);
    setDraft({text:"",category:"merch"}); setSubmitting(false);
  };

  const markHelpful = (id) => {
    if(helpfulVoted[id]) return;
    setTips(ts=>ts.map(t=>t.id===id?{...t,helpful:t.helpful+1}:t));
    setHelpfulVoted(v=>({...v,[id]:true}));
  };

  return (
    <div style={{ marginBottom:16 }}>
      <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:11 }}>
        <p style={{ ...VS.softSectionHeader() }}>Fan-Sourced Venue Tips</p>
        <button onClick={()=>setSubmitting(v=>!v)} style={{ background:`${col}18`,border:`1px solid ${col}33`,borderRadius:9,padding:"5px 10px",color:col,fontSize:10,fontFamily:"'Epilogue',sans-serif",fontWeight:700,cursor:"pointer" }}>+ Add Tip</button>
      </div>

      {submitting && (
        <div style={{ background:C.surfaceHi,border:`1.5px solid ${col}33`,borderRadius:14,padding:14,marginBottom:12,animation:"up .2s ease" }}>
          <select value={draft.category} onChange={e=>setDraft(d=>({...d,category:e.target.value}))} style={{ width:"100%",padding:"8px 10px",borderRadius:10,background:C.surface,border:`1px solid ${C.border}`,color:C.text,fontSize:12,marginBottom:9,outline:"none" }}>
            {Object.entries(CAT_LABELS).filter(([k])=>k!=="all").map(([k,v])=><option key={k} value={k}>{v}</option>)}
          </select>
          <textarea value={draft.text} onChange={e=>setDraft(d=>({...d,text:e.target.value}))} placeholder="Share a venue tip with fans..." style={{ width:"100%",height:64,background:C.surface,border:`1.5px solid ${C.border}`,borderRadius:10,color:C.text,fontSize:12,resize:"none",outline:"none",fontFamily:"'Instrument Sans',sans-serif",padding:"9px 12px",marginBottom:9 }} autoFocus />
          <div style={{ display:"flex",gap:8 }}>
            <button onClick={submitTip} disabled={!draft.text.trim()} style={{ flex:1,padding:"9px",borderRadius:11,background:draft.text.trim()?`linear-gradient(140deg,${col}cc,${col}88)`:`${col}33`,border:"none",color:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12,cursor:"pointer" }}>Submit Tip</button>
            <button onClick={()=>setSubmitting(false)} style={{ padding:"9px 14px",borderRadius:11,background:C.surface,border:`1px solid ${C.border}`,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:600,fontSize:12,cursor:"pointer" }}>Cancel</button>
          </div>
        </div>
      )}

      {/* Category filters */}
      <div style={{ display:"flex",gap:6,overflowX:"auto",scrollbarWidth:"none",marginBottom:10,paddingBottom:2 }}>
        {Object.entries(CAT_LABELS).map(([k,v])=>(
          <span key={k} onClick={()=>setCatFilter(k)} className="tap" style={{ flexShrink:0,padding:"4px 10px",borderRadius:99,fontSize:10,fontFamily:"'Epilogue',sans-serif",fontWeight:700,cursor:"pointer",background:catFilter===k?col:`${col}10`,color:catFilter===k?C.bg:C.textMid,border:`1px solid ${catFilter===k?col:C.border}` }}>{v}</span>
        ))}
      </div>

      {/* Tips list */}
      {filtered.map(tip=>(
        <div key={tip.id} style={{ background:C.surface,border:`1px solid ${C.border}`,borderRadius:14,padding:"11px 13px",marginBottom:8 }}>
          <div style={{ display:"flex",gap:8,alignItems:"flex-start" }}>
            <div style={{ flex:1 }}>
              <div style={{ display:"flex",gap:6,alignItems:"center",marginBottom:4 }}>
                <span style={{ fontSize:10,background:`${col}14`,color:col,borderRadius:99,padding:"1px 7px",fontFamily:"'Epilogue',sans-serif",fontWeight:700 }}>{CAT_LABELS[tip.category]||tip.category}</span>
                <span style={{ fontSize:9.5,color:C.textDim }}>{tip.author} · {tip.time}</span>
              </div>
              <p style={{ fontSize:12.5,color:C.text,lineHeight:1.55 }}>{tip.text}</p>
            </div>
          </div>
          <div style={{ display:"flex",gap:10,marginTop:8,alignItems:"center" }}>
            <button onClick={()=>markHelpful(tip.id)} style={{ display:"flex",gap:5,alignItems:"center",background:"none",border:"none",color:helpfulVoted[tip.id]?C.mint:C.textDim,fontSize:11,cursor:"pointer",fontFamily:"'Epilogue',sans-serif",fontWeight:600 }}>
              {helpfulVoted[tip.id]?"✓ Helpful":"👍 Helpful"} <span style={{ color:C.mint }}>{tip.helpful+(helpfulVoted[tip.id]?1:0)}</span>
            </button>
          </div>
        </div>
      ))}
      {filtered.length===0&&<p style={{ fontSize:11.5,color:C.textDim,textAlign:"center",padding:"16px 0" }}>No tips for this category yet — be the first!</p>}
    </div>
  );
}

// ─── CONCERT DAY BANNER — auto-shown on Home when show is imminent/today ──────
// Renders nothing for expired concerts (>72h after last show) so stale data
// never appears on Home. Afterglow phase (0–72h post-show) shows a memory prompt.
function ConcertDayBanner({ go }) {
  const concert = MOCK_CONCERTS[0];
  const col     = concert.color || C.pink;
  const status  = getConcertStatus(concert);

  // Purge stale localStorage flag left over from previous builds
  useEffect(() => {
    if (status === 'expired' || status === 'future' || status === 'no_date') {
      ls.del('backstage_concertday_active');
    }
  }, [status]);

  if (status === 'expired' || status === 'future' || status === 'no_date') return null;

  if (status === 'afterglow') {
    return (
      <div onClick={()=>go('capsule')} className="tap" style={{ margin:"0 18px 18px", borderRadius:18, cursor:"pointer", background:`linear-gradient(140deg,${col}18,${col}08)`, border:`1.5px solid ${col}33`, padding:"13px 16px", display:"flex", gap:12, alignItems:"center" }}>
        <div style={{ fontSize:26 }}>🌙</div>
        <div style={{ flex:1 }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:13.5,color:C.text,marginBottom:2 }}>How was the show?</p>
          <p style={{ fontSize:11,color:C.textMid }}>{concert.name} · Add your memories to the Capsule</p>
        </div>
        <span style={{ fontSize:13,color:col }}>→</span>
      </div>
    );
  }

  // today / soon / upcoming — show live countdown
  return <ConcertDayBannerActive concert={concert} status={status} go={go} />;
}

function ConcertDayBannerActive({ concert, status, go }) {
  const col = concert.color || C.pink;
  // Pass ISO date + raw showTime to the countdown hook so it parses correctly
  const countdownStr = useConcertCountdown(
    concert.showTime,
    concert.startDateISO ? `${concert.startDateISO} ${concert.showTime}` : concert.date
  );
  const statusLabel = status === 'today' ? 'Concert Day Mode Active'
                    : status === 'soon'  ? 'Show Tomorrow'
                    :                     'Coming Up';
  // Display the hour portion only ("6h") when countdown is hours out
  const hourMatch = countdownStr?.match(/^(\d+)h /);
  return (
    <div onClick={()=>go("concertday")} className="tap" style={{ margin:"0 18px 18px", borderRadius:20, overflow:"hidden", cursor:"pointer", position:"relative", background:`linear-gradient(140deg,${col}28,${col}0e)`, border:`1.5px solid ${col}55`, boxShadow:`0 8px 28px ${col}20` }}>
      <div style={{ position:"absolute",top:0,left:0,right:0,height:1.5,background:`linear-gradient(90deg,transparent,${col}99,transparent)` }} />
      <div style={{ padding:"13px 16px",display:"flex",gap:12,alignItems:"center" }}>
        <div style={{ width:44,height:44,borderRadius:13,background:`${col}22`,border:`1.5px solid ${col}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0,animation:"concertPulse 2s ease-in-out infinite" }}>🎤</div>
        <div style={{ flex:1 }}>
          <div style={{ display:"flex",gap:6,alignItems:"center",marginBottom:3 }}>
            {status === 'today' && <div style={{ width:6,height:6,borderRadius:"50%",background:C.rose,animation:"pulse 1s ease infinite" }} />}
            <p style={{ fontSize:9,color:status==='today'?C.rose:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.1em" }}>{statusLabel}</p>
          </div>
          <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:14,color:C.text,marginBottom:1 }}>{concert.name}</p>
          <p style={{ fontSize:10.5,color:C.textMid }}>📍 {concert.venue} · {concert.city}</p>
        </div>
        <div style={{ textAlign:"center",background:`${col}1c`,borderRadius:10,padding:"6px 10px",minWidth:50 }}>
          {hourMatch ? (
            <>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:18,color:col,lineHeight:1 }}>{hourMatch[1]}h</p>
              <p style={{ fontSize:8,color:C.textMid }}>to show</p>
            </>
          ) : countdownStr ? (
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:10,color:col,lineHeight:1.4 }}>{countdownStr}</p>
          ) : (
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:10,color:col }}>Soon</p>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── CONCERT DAY MODE — full-screen experience ────────────────────────────────
