// ─── PUBLIC PROFILE PAGE (/u/:username or /@:username) ───────────────────────
// Shown when someone follows a shareable profile link.
// Logged-in → shows profile + Add to Circle.
// Logged-out → prompts sign-up, then returns to this URL.
function ProfilePublicPage({ username }) {
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [notFound, setNotFound] = useState(false);
  const [added, setAdded] = useState(false);
  const [copied, setCopied] = useState(false);

  // Check if we have a session (simple — just try reading localStorage)
  const session = ls.get('backstage_session');
  const isLoggedIn = !!(session?.user?.id);
  const myId = session?.user?.id;

  useEffect(() => {
    const handle = username.replace(/^@/, '').toLowerCase();
    // Try API first, fall back gracefully
    fetch(`${API_URL || ''}/api/profile/by-username/${encodeURIComponent(handle)}`)
      .then(r => r.json())
      .then(d => {
        if (d?.error) { setNotFound(true); }
        else {
          setProfile(d);
          const store = readFriendRequestStore();
          const alreadyRequested = store.outgoing.some(r => (r.receiver_id || r.user?.id) === d.id);
          const alreadyFriends = ls.get("backstage_friends", []).some(f => (f.id || f.profileId) === d.id && f.status === "accepted");
          if (alreadyRequested || alreadyFriends) setAdded(true);
        }
      })
      .catch(() => setNotFound(true))
      .finally(() => setLoading(false));
  }, [username]);

  const handleAdd = () => {
    if (!isLoggedIn) {
      // Save the return URL and send to auth
      ls.set('backstage_return_to', window.location.href);
      window.location.href = '/';
      return;
    }
    if (profile?.id) {
      // Fire-and-forget request; also persist to localStorage
      api.post('/api/friends/request', { targetUserId: profile.id }).then(r=>{
        const store = readFriendRequestStore();
        const outgoingReq = { id:r?.request?.id || `req-${Date.now()}`, user:profile, receiver_id:profile.id, status:"pending", created_at:new Date().toISOString() };
        ls.set("backstage_friend_requests", { ...store, outgoing:upsertById(store.outgoing, outgoingReq) });
      }).catch(()=>{});
      const statuses = ls.get('backstage_circle_statuses', {});
      ls.set('backstage_circle_statuses', { ...statuses, [profile.id]: 'sent' });
    }
    setAdded(true);
  };

  const profileUrl = `${window.location.origin}/u/${username}`;
  const copyLink = () => {
    navigator.clipboard?.writeText(profileUrl).catch(()=>{});
    setCopied(true); setTimeout(()=>setCopied(false),2000);
  };

  const bg = { minHeight:'100vh', background:C.bg, color:C.text, fontFamily:"'Instrument Sans',sans-serif", display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:'32px 24px' };

  if (loading) return (
    <div style={bg}>
      <div style={{ width:32,height:32,borderRadius:'50%',border:`3px solid ${C.accent}`,borderTopColor:'transparent',animation:'rotate .7s linear infinite' }} />
    </div>
  );

  if (notFound) return (
    <div style={bg}>
      <div style={{ textAlign:'center', maxWidth:360 }}>
        <div style={{ fontSize:48,marginBottom:16 }}>🔭</div>
        <h1 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:22,marginBottom:8 }}>Profile not found</h1>
        <p style={{ fontSize:14,color:C.textMid,marginBottom:24,lineHeight:1.6 }}>@{username} doesn't have a Backstage profile yet — or the link may have changed.</p>
        <a href="/" style={{ display:'inline-block',padding:'12px 24px',borderRadius:99,background:C.accent,color:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:14,textDecoration:'none' }}>Open Backstage →</a>
      </div>
    </div>
  );

  const fandoms = profile?.fandoms || [];
  const displayName = profile?.display_name || profile?.username || username;
  const isSelf = myId && profile?.id === myId;

  return (
    <div style={{ minHeight:'100vh', background:C.bg, color:C.text, fontFamily:"'Instrument Sans',sans-serif" }}>
      {/* Header */}
      <div style={{ background:`linear-gradient(160deg,${C.plum}80,${C.cosmic})`,padding:'32px 24px 24px',textAlign:'center',position:'relative',overflow:'hidden' }}>
        <div style={{ position:'absolute',top:-40,left:'50%',transform:'translateX(-50%)',width:200,height:200,borderRadius:'50%',background:`radial-gradient(circle,${C.accent}15,transparent 70%)`,pointerEvents:'none' }} />
        {/* Avatar */}
        <div style={{ width:72,height:72,borderRadius:'50%',background:`linear-gradient(135deg,${C.accent},${C.berry})`,display:'flex',alignItems:'center',justifyContent:'center',fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:28,color:C.bg,margin:'0 auto 12px',border:`3px solid ${C.accent}88`,boxShadow:`0 0 28px ${C.accent}40`,position:'relative',zIndex:1 }}>
          {String(displayName).slice(0,1).toUpperCase()}
        </div>
        {/* Name + VIP */}
        <div style={{ display:'flex',alignItems:'center',justifyContent:'center',gap:7,marginBottom:4,position:'relative',zIndex:1 }}>
          <h1 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:20,margin:0 }}>{displayName}</h1>
          {profile?.is_vip&&<span style={{ padding:'2px 8px',borderRadius:99,background:`${C.gold}22`,border:`1px solid ${C.gold}55`,fontSize:9,color:C.gold,fontFamily:"'Epilogue',sans-serif",fontWeight:700 }}>VIP ✦</span>}
        </div>
        <p style={{ fontSize:12,color:C.textMid,marginBottom:10,position:'relative',zIndex:1 }}>@{profile?.username || username}</p>
        {/* Fandom badges */}
        {fandoms.length > 0 && (
          <div style={{ display:'flex',gap:5,justifyContent:'center',flexWrap:'wrap',position:'relative',zIndex:1 }}>
            {fandoms.slice(0,5).map(f=>(
              <span key={f} style={{ padding:'3px 10px',borderRadius:99,background:`${C.accent}22`,border:`1px solid ${C.accent}44`,fontSize:10,color:C.accent,fontFamily:"'Epilogue',sans-serif",fontWeight:700 }}>{f}</span>
            ))}
          </div>
        )}
      </div>

      {/* Body */}
      <div style={{ padding:'20px 24px',maxWidth:420,margin:'0 auto' }}>
        {profile?.bio && (
          <p style={{ fontSize:13,color:C.textMid,lineHeight:1.7,marginBottom:16,textAlign:'center' }}>{profile.bio}</p>
        )}
        {profile?.city && (
          <p style={{ fontSize:12,color:C.textDim,textAlign:'center',marginBottom:20 }}>📍 {profile.city}</p>
        )}

        {/* CTA */}
        {!isSelf && (
          <div style={{ display:'flex',flexDirection:'column',gap:10,marginBottom:20 }}>
            {!isLoggedIn ? (
              <>
                <button onClick={handleAdd} style={{ padding:'14px',borderRadius:14,background:`linear-gradient(135deg,${C.accent},${C.berry})`,border:'none',color:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:15,cursor:'pointer',boxShadow:`0 0 20px ${C.accent}40` }}>
                  Join Backstage to add @{profile?.username||username} ✦
                </button>
                <p style={{ fontSize:11,color:C.textDim,textAlign:'center' }}>Free to join · No credit card</p>
              </>
            ) : added ? (
              <div style={{ padding:'14px',borderRadius:14,background:`${C.mint}18`,border:`1.5px solid ${C.mint}44`,textAlign:'center' }}>
                <p style={{ color:C.mint,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:14 }}>✦ Circle request sent!</p>
                <p style={{ fontSize:11,color:C.textMid,marginTop:4 }}>You'll be connected when they accept.</p>
              </div>
            ) : (
              <button onClick={handleAdd} style={{ padding:'14px',borderRadius:14,background:`linear-gradient(135deg,${C.accent},${C.berry})`,border:'none',color:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:15,cursor:'pointer',boxShadow:`0 0 20px ${C.accent}40` }}>
                Add @{profile?.username||username} to My Circle ✦
              </button>
            )}
          </div>
        )}

        {/* Copy / open app links */}
        <div style={{ display:'flex',gap:8 }}>
          <button onClick={copyLink} style={{ flex:1,padding:'11px',borderRadius:12,background:copied?`${C.mint}22`:C.surface,border:`1.5px solid ${copied?C.mint:C.border}`,color:copied?C.mint:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12,cursor:'pointer',transition:'all .2s' }}>
            {copied?'✓ Copied':'🔗 Copy Link'}
          </button>
          <a href="/" style={{ flex:1,padding:'11px',borderRadius:12,background:C.surfaceHi,border:`1.5px solid ${C.border}`,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12,cursor:'pointer',textAlign:'center',textDecoration:'none' }}>
            Open App →
          </a>
        </div>
      </div>
    </div>
  );
}

// ─── APP ERROR BOUNDARY ───────────────────────────────────────────────────────
// Wraps AuthProvider so it catches errors thrown in AuthProvider itself, not
// just its children. Root cause: StrictMode double-mount + duplicate createRoot
// (now removed) caused a render loop. This boundary stops it cleanly and logs
// the real error so we can diagnose any recurrence.
class AppErrorBoundary extends React.Component {
  constructor(props) { super(props); this.state = { error: null }; }
  static getDerivedStateFromError(error) { return { error }; }
  componentDidCatch(error, info) {
    // Log the real error — this is what was missing when the loop was firing.
    // componentStack shows exactly where in the tree the throw happened.
    console.error(
      '[Backstage] render error caught by AppErrorBoundary\n',
      'Error:', error?.message || error,
      '\nStack:', error?.stack?.split('\n').slice(0,6).join('\n'),
      '\nComponent stack:', info?.componentStack?.split('\n').slice(0,8).join('\n')
    );
  }
  render() {
    if (this.state.error) {
      return (
        <div style={{ minHeight:"100vh", display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", background:"#07050f", color:"#ede8ff", fontFamily:"'Instrument Sans',sans-serif", padding:32, textAlign:"center" }}>
          <p style={{ fontSize:32, marginBottom:12 }}>✦</p>
          <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:18, marginBottom:8 }}>Something went wrong</p>
          <p style={{ fontSize:13, color:"#a090cc", marginBottom:24, maxWidth:260, lineHeight:1.6 }}>Backstage hit an unexpected error. Your data is safe.</p>
          <button onClick={()=>this.setState({error:null})} style={{ padding:"10px 24px", borderRadius:99, background:"#b8a2ff", color:"#07050f", fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:13, border:"none", cursor:"pointer" }}>Try again</button>
        </div>
      );
    }
    return this.props.children;
  }
}

// ─── ROOT APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const p = window.location.pathname;
  if (p === '/privacy')        return <PrivacyPage />;
  if (p === '/terms')          return <TermsPage />;
  if (p === '/support')        return <SupportPage />;
  if (p === '/delete-account') return <DeleteAccountPage />;
  // Shareable profile links: /u/:username or /@:username
  const uMatch = p.match(/^\/(?:u\/|@)(.+)$/);
  if (uMatch) return <ProfilePublicPage username={uMatch[1]} />;
  return <AppErrorBoundary><AuthProvider><AppInner /></AuthProvider></AppErrorBoundary>;
}

const _IS_CAPSULE_PATH = typeof window!=="undefined" && (window.location.pathname==="/capsule"||window.location.pathname==="/capsule/");

// Preserve capsule/invite context through the signup flow
if(_IS_CAPSULE_PATH && typeof window!=="undefined") {
  const params = new URLSearchParams(window.location.search);
  const ctx = { capsuleId:"bts-lv-1", inviteCode:params.get("ref")||null, landedAt:Date.now() };
  ls.set("backstage_capsule_context", ctx);
  ls.set("backstage_pending_invite", ctx.inviteCode ? { code:ctx.inviteCode, capsuleId:ctx.capsuleId } : null);
}

// ─── STABLE MODAL WRAPPER ────────────────────────────────────────────────────
// MUST be defined outside AppInner — if defined inside, every AppInner re-render
// creates a new function reference, causing React to unmount/remount all children
// (including DirectMessages), wiping local state like activeConvo.
function ModalWrapper({ children }) {
  // position:absolute;inset:0 positions against the app-shell's border edge, not its
  // padding edge — so it bypasses .app-shell's own safe-area-inset-top padding.
  // Every full-screen modal needs that clearance re-applied here, once, centrally.
  return (
    <div style={{ position:"absolute",inset:0,zIndex:300,background:`linear-gradient(160deg,${C.cosmic} 0%,${C.bg} 50%,${C.surfaceMid} 100%)`,display:"flex",flexDirection:"column",animation:"in .18s ease" }}>
      <div style={{ position:"absolute",top:0,right:0,width:200,height:200,borderRadius:"50%",background:`radial-gradient(circle,${C.berry}06,transparent 70%)`,pointerEvents:"none",zIndex:0 }} />
      <div style={{ position:"absolute",bottom:100,left:0,width:150,height:150,borderRadius:"50%",background:`radial-gradient(circle,${C.accent}05,transparent 70%)`,pointerEvents:"none",zIndex:0 }} />
      <div style={{ position:"relative",zIndex:1,flex:1,display:"flex",flexDirection:"column",overflow:"hidden",paddingTop:"calc(env(safe-area-inset-top,0px) + 10px)" }}>{children}</div>
    </div>
  );
}

function AppInner() {
  const auth = useAuth();
  const [themeMode, setThemeModeState] = useState(()=>ls.get("backstage_light_mode",false)?"light":"dark");
  // Mutate the shared C palette in place before rendering anything below — every
  // child function component reads C.xxx live during its own render, so this is
  // the one place a theme switch has to happen for the whole tree to reflect it.
  applyThemeMode(themeMode);
  const setThemeMode = (mode)=>{ ls.set("backstage_light_mode", mode==="light"); setThemeModeState(mode); };
  const [user, setUser] = useState(()=>normalizeProfile(ls.get("backstage_session")?.user)||null);
  const [appState, setAppState] = useState(()=>{
    const u = normalizeProfile(ls.get("backstage_session")?.user);
    if(u && canEnterApp(u)) return "main";
    if(u?.id) return "onboarding"; // authenticated but profile incomplete
    return "auth"; // no session — show welcome/login screen
  });
  // Once the user reaches "main", never push them back to onboarding from a
  // background profile re-fetch. onAuthStateChange fires on token refresh and
  // the freshly-fetched profile can transiently lack fandoms if the DB row is
  // sparse, causing canEnterApp to fail on an otherwise valid existing user.
  // hasReachedMain: true if the user has ever completed onboarding.
  // Check both the session cache AND the per-user profile key so a cleared
  // backstage_session (new device, cleared storage) doesn't trigger onboarding
  // for a user whose profile is already complete in per-user localStorage.
  const _initSessUser  = normalizeProfile(ls.get("backstage_session")?.user);
  const _initUserId    = _initSessUser?.id || ls.get("backstage_pending_uid");
  const _initPerUser   = _initUserId ? normalizeProfile(ls.get(`backstage_profile_${_initUserId}`)) : null;
  const hasReachedMain = useRef(canEnterApp(_initSessUser) || canEnterApp(_initPerUser));
  const [tab, setTab] = useState("community");
  // Auto-open capsule modal if signed-in user lands on /capsule
  const [modal, setModal] = useState(()=>_IS_CAPSULE_PATH&&canEnterApp(normalizeProfile(ls.get("backstage_session")?.user))?"capsule":null);
  const [fromCapsule, setFromCapsule] = useState(_IS_CAPSULE_PATH);
  const [showCapsuleLanding, setShowCapsuleLanding] = useState(()=>_IS_CAPSULE_PATH&&!ls.get("backstage_session")?.user);
  // Capsule preview: signed-out fan sees the capsule before being asked to sign up
  const [showCapsulePreview, setShowCapsulePreview] = useState(false);
  const [cards, setCards] = useState(MOCK_CARDS);
  const [notif, setNotif] = useState(null);
  const [showNotifPrompt, setShowNotifPrompt] = useState(false);
  const [showSmartNotifs, setShowSmartNotifs] = useState(false);
  const weatherData = MOCK_WEATHER;

  // ── VIP — backed by Supabase users.is_vip ───────────────────────────────────
  // POST /api/subscriptions/checkout | GET /api/subscriptions/status
  const [isVip, setIsVip] = useState(()=>{
    const u = ls.get("backstage_session")?.user;
    // Check session, per-user cache, and global cache (global covers cleared-session case after sign-out is NOT called)
    return hasVipEntitlement(u) || getCachedVip(u) || ls.get("backstage_is_vip", false) === true;
  });
  const [showUpgradeModal, setShowUpgradeModal] = useState(false);
  const [showVipCelebration, setShowVipCelebration] = useState(false);
  const [showVipTour, setShowVipTour] = useState(false);
  // Public user profile — lifted to root so it covers tabs + nav (not a modal-internal overlay)
  const [publicProfileFan, setPublicProfileFan] = useState(null); // compact card
  const [fullProfileFan,   setFullProfileFan]   = useState(null); // full rich profile (above compact card)

  useEffect(()=>{
    const nextUser = normalizeProfile(auth.user || ls.get("backstage_session")?.user);
    if (!nextUser) {
      // No authenticated user — once auth finishes loading, go to welcome screen.
      if (!auth.loading) setAppState("auth");
      return;
    }
    setUser(nextUser);
    // Era boards — hydrate from server on fresh devices (local store empty).
    // Never overwrites existing local data; server blob is pushed by syncEraBoardsToServer.
    try {
      const localBoards = JSON.parse(localStorage.getItem("backstage_era_boards_v2") || "{}");
      const remoteBoards = nextUser.era_boards;
      if (!Object.keys(localBoards).length && remoteBoards && typeof remoteBoards === 'object' && Object.keys(remoteBoards).length) {
        localStorage.setItem("backstage_era_boards_v2", JSON.stringify(remoteBoards));
        window.dispatchEvent(new CustomEvent("backstage:eraBoardsUpdated"));
      }
    } catch {}
    // My World — hydrate collection stores from server on fresh devices only
    // (none of the My World keys present locally). Never overwrites local data.
    try {
      const remoteWorld = nextUser.my_world;
      if (remoteWorld && typeof remoteWorld === 'object' && Object.keys(remoteWorld).length) {
        const anyLocal = MY_WORLD_KEYS.some(k => localStorage.getItem(k) != null);
        if (!anyLocal) {
          MY_WORLD_KEYS.forEach(k => { if (remoteWorld[k] !== undefined) localStorage.setItem(k, JSON.stringify(remoteWorld[k])); });
          // Re-derive per-concert "saved to world" flags from the saved capsules list
          const savedCaps = Array.isArray(remoteWorld["backstage_saved_capsules"]) ? remoteWorld["backstage_saved_capsules"] : [];
          savedCaps.forEach(c => { if (c && c.id != null) localStorage.setItem(`backstage_saved_capsule_${c.id}`, "true"); });
        }
      }
    } catch {}
    // Sync VIP from the merged profile (/api/users/me SELECT * includes is_vip).
    // IMPORTANT: only SET VIP to true here — never set it to false.
    // Reason: auth.user fires twice (cached session, then API result), and the
    // merged profile can transiently have is_vip:false if the local cache is stale.
    // Revocation (setIsVip false) is handled exclusively by the VIP sync effect
    // (/api/subscriptions/status), which is the backend-authoritative source.
    const vipFromProfile = hasVipEntitlement(nextUser) || getCachedVip(nextUser);
    if (vipFromProfile) {
      setIsVip(true);
      setCachedVip(nextUser, true);
    }
    const sess = ls.get('backstage_session');
    if (sess?.user) ls.set('backstage_session', {...sess, user:{...sess.user, is_vip: sess.user.is_vip || vipFromProfile}});
    if (canEnterApp(nextUser)) {
      hasReachedMain.current = true;
      markOnboardingComplete(nextUser);
      setAppState("main");
    } else if (!hasReachedMain.current) {
      // Before routing to onboarding, check per-user localStorage. A returning
      // user whose backstage_session was cleared (new device, cache cleared) but
      // whose full profile is stored under backstage_profile_${id} should skip
      // onboarding entirely.
      const savedProfile = nextUser?.id ? normalizeProfile(ls.get(`backstage_profile_${nextUser.id}`)) : null;
      if (savedProfile && canEnterApp(savedProfile)) {
        setUser(savedProfile);
        ls.set('backstage_session', { user: savedProfile });
        hasReachedMain.current = true;
        markOnboardingComplete(savedProfile);
        setAppState("main");
      } else if (!auth.loading) {
        // auth.loading = false means the full profile has loaded (or failed). Safe to show onboarding.
        ls.set("backstage_pending_uid", nextUser.id);
        setAppState("onboarding");
        setModal(null);
      }
      // If auth.loading is still true, do nothing — the profile may still be arriving.
    }
  },[auth.user, auth.loading]);

  // After login: if the user came from a /u/:username profile link, redirect them back.
  useEffect(()=>{
    if(appState==="main"){
      const returnTo = ls.get('backstage_return_to');
      if(returnTo){
        ls.del('backstage_return_to');
        window.location.href = returnTo;
      }
    }
  },[appState]);

  // Keeps friend requests / Circle / notifications fresh without a logout-login —
  // Supabase Realtime pushes an instant refresh on any relevant DB change; a 15s
  // poll plus a tab-focus refetch cover the case where Realtime never connects.
  // Every trigger (realtime event, poll tick, focus) calls the exact same
  // refreshSocial() so there's one code path to reason about.
  useEffect(()=>{
    if(appState!=="main" || !auth.tokenReady) return;
    const refreshSocial = () => {
      syncBackendNotifications().catch(()=>{});
      Promise.all([syncBackendFriendRequests(), syncBackendCircle()]).then(([reqStore, circleList]) => {
        const acceptedIds = (circleList || []).filter(f => f.status === "accepted").map(f => f.id);
        const pendingOutIds = (reqStore?.outgoing || []).map(r => r.receiver_id || r.user?.id).filter(Boolean);
        reconcileCircleStatuses(acceptedIds, pendingOutIds);
      }).catch(()=>{});
    };
    refreshSocial();
    const iv = setInterval(refreshSocial, 15000);
    const onFocus = () => { if(document.visibilityState==="visible") refreshSocial(); };
    document.addEventListener("visibilitychange", onFocus);
    window.addEventListener("focus", onFocus);

    let channel = null;
    if (_supabase && auth.user?.id) {
      channel = _supabase.channel(`social-${auth.user.id}`)
        .on("postgres_changes", { event:"*", schema:"public", table:"friend_requests", filter:`receiver_id=eq.${auth.user.id}` }, refreshSocial)
        .on("postgres_changes", { event:"*", schema:"public", table:"friend_requests", filter:`sender_id=eq.${auth.user.id}` }, refreshSocial)
        .on("postgres_changes", { event:"*", schema:"public", table:"friends", filter:`user_id=eq.${auth.user.id}` }, refreshSocial)
        .on("postgres_changes", { event:"*", schema:"public", table:"notifications", filter:`user_id=eq.${auth.user.id}` }, refreshSocial)
        .subscribe();
    }

    return ()=>{
      clearInterval(iv);
      document.removeEventListener("visibilitychange", onFocus);
      window.removeEventListener("focus", onFocus);
      if (channel) _supabase.removeChannel(channel);
    };
  },[appState, auth.tokenReady, auth.user?.id]);

  // ── BROWSER BACK BUTTON (PWA / web) ──────────────────────────────────────────
  // The app uses React state for navigation — the browser has no history of
  // in-app moves. We maintain a 2-level stack: level-0 is the back-stop,
  // level-1 is "somewhere inside the app." Each back press pops to level-0,
  // we intercept it, close the deepest open thing (modal → non-home tab → exit),
  // then re-push level-1 so the next back press works the same way.
  useEffect(()=>{
    if(appState!=="main") return;
    // Seed the 2-level stack when entering main state
    window.history.replaceState({ bsLevel:0 }, '');
    window.history.pushState({ bsLevel:1 }, '');
  },[appState]);

  useEffect(()=>{
    if(appState!=="main") return;
    const onPop = () => {
      if(modal){
        // Close the open modal and re-seal the back-stop
        setModal(null);
        window.history.pushState({ bsLevel:1 }, '');
        return;
      }
      if(tab!=="community"){
        // Navigate to the default tab and re-seal
        setTab("community");
        window.history.pushState({ bsLevel:1 }, '');
        return;
      }
      // Already at root — allow the browser to leave the site naturally
    };
    window.addEventListener('popstate', onPop);
    return ()=>window.removeEventListener('popstate', onPop);
  },[appState, modal, tab]);

  // Boot: sync VIP status from backend on session restore.
  // Depends on auth.tokenReady so it only fires after api._token is actually set.
  // auth.user?.id alone is not sufficient — it becomes truthy from the cached
  // session before getSession() resolves, causing an unauthenticated call that
  // returns is_vip:false and wipes VIP state.
  useEffect(()=>{
    if(!auth.user?.id || !auth.tokenReady || appState!=="main") return;

    const applyVip = (source, sinceOverride) => {
      setIsVip(true);
      setCachedVip(auth.user, true);
      setUser(u=>{ if(!u) return u; return {...u, is_vip:true, vip_source:source}; });
      const sess = ls.get('backstage_session');
      if(sess?.user) ls.set('backstage_session', {...sess, user:{...sess.user, is_vip:true, vip_source:source}});
    };

    const retryDelays = [5_000, 15_000, 40_000];
    const runStatusCheck = (attempt = 0) => {
      api.get('/api/subscriptions/status').then(d=>{
        if(d?.error || d?.is_vip===undefined){
          // Auth refresh, Render cold starts, and transient DB errors are not
          // proof that a paid account was revoked. Keep cached VIP and retry.
          console.warn(`[VIP sync] status check failed (attempt ${attempt+1}/${retryDelays.length+1}):`, d?.error || 'malformed response');
          if(attempt < retryDelays.length) setTimeout(()=>runStatusCheck(attempt + 1), retryDelays[attempt]);
          else console.error('[VIP sync] gave up after all retries — isVip may be stale until next app reload');
          return;
        }
        const active = hasVipEntitlement({is_vip:d.is_vip, vip_source:d.vip_source, vip_expires_at:d.vip_expires_at});
        console.log('[VIP sync]', auth.user?.email, '| db is_vip:', d.is_vip, '| vip_source:', d.vip_source, '| founder_number:', d.founder_number, '| gate isVip:', active);
        setIsVip(active);
        setCachedVip(auth.user, active);
        setUser(u=>{
          if(!u) return u;
          return {...u, is_vip:active, vip_source:d.vip_source||u.vip_source, vip_expires_at:d.vip_expires_at||u.vip_expires_at, founder_number:d.founder_number??u.founder_number};
        });
        const sess = ls.get('backstage_session');
        if(sess?.user) ls.set('backstage_session', {...sess, user:{...sess.user, is_vip:active, vip_source:d.vip_source||sess.user.vip_source, founder_number:d.founder_number??sess.user.founder_number}});
        // Evict any stale random founder number from localStorage — DB is the source of truth
        const storedFp = ls.get('backstage_founder_profile', {});
        if(storedFp.number !== undefined) ls.set('backstage_founder_profile', { message: storedFp.message });

        // ── Reconciliation: "paid before signup" recovery ─────────────────────
        // If DB says not VIP, check Stripe for a completed payment for this email.
        // Throttled to once per hour per user to avoid hammering Stripe API.
        if(!active && auth.user?.id){
          const throttleKey = `backstage_last_reconcile_${auth.user.id}`;
          const lastRun = ls.get(throttleKey, 0);
          if(Date.now() - lastRun > 3_600_000){
            ls.set(throttleKey, Date.now());
            api.post('/api/subscriptions/reconcile').then(r=>{
              if(r?.reconciled){
                applyVip(r.vip_source || 'founder');
                setShowVipCelebration(true);
              }
            }).catch(()=>{});
          }
        }
      }).catch(err=>{
        console.warn(`[VIP sync] status check network error (attempt ${attempt+1}/${retryDelays.length+1}):`, err?.message);
        if(attempt < retryDelays.length) setTimeout(()=>runStatusCheck(attempt + 1), retryDelays[attempt]);
      });
    };
    runStatusCheck();
  },[auth.user?.id, auth.tokenReady, appState]);

  const handleAccountRefresh = ({ profile, subscription }) => {
    const nextUser = normalizeProfile({ ...(user || {}), ...(profile || {}), ...(subscription || {}) });
    if(nextUser){
      setUser(nextUser);
      const sess = ls.get('backstage_session');
      ls.set('backstage_session', { ...(sess || {}), user:{ ...(sess?.user || {}), ...nextUser } });
      if(nextUser.id) ls.set(`backstage_profile_${nextUser.id}`, { ...ls.get(`backstage_profile_${nextUser.id}`, {}), ...nextUser });
    }
    if(subscription?.is_vip != null){
      const active = hasVipEntitlement(subscription) || hasVipEntitlement(nextUser);
      setIsVip(active);
      setCachedVip(nextUser || user, active);
    } else if(hasVipEntitlement(nextUser)){
      setIsVip(true);
      setCachedVip(nextUser, true);
    }
  };

  // Boot: load photocard collection from user_cards table.
  // Depends on auth.tokenReady so it only fires after api._token is set.
  useEffect(()=>{
    if(!user?.id || !auth.tokenReady || appState!=="main" || !API_URL) return;
    api.get('/api/cards').then(d=>{ if(d?.cards?.length) setCards(d.cards); }).catch(()=>{});
  },[user?.id, auth.tokenReady, appState]);

  // Incomplete profile nudge — shown 24h after signup, max once per 72h, stops when fandoms set
  useEffect(()=>{
    if(!user?.id || !auth.tokenReady || appState!=="main") return;
    const hasFandoms = (user.fandoms||user.favorite_groups||[]).length > 0;
    if(hasFandoms) return;
    const nudgeKey = `backstage_nudge_${user.id}`;
    const lastNudge = ls.get(nudgeKey, 0);
    const nowMs = Date.now();
    const signupMs = user.created_at ? new Date(user.created_at).getTime() : nowMs;
    if(nowMs - signupMs < 24*60*60*1000) return; // < 24h since signup
    if(lastNudge && nowMs - lastNudge < 72*60*60*1000) return; // shown < 72h ago
    ls.set(nudgeKey, nowMs);
    setTimeout(()=>{
      setNotif({ title:"Your Stage is waiting ✦", body:"Add your fandoms, bias, and concert era to complete your profile.", icon:"✦", color:C.accent });
      setTimeout(()=>setNotif(null), 6000);
    }, 3000); // delay so it doesn't clash with initial render
  },[user?.id, auth.tokenReady, appState]);

  const handleUpgrade = async (selectedPlan = "annual") => {
    // Guard: already VIP — nothing to upgrade
    if (isVip || hasVipEntitlement(user)) return;
    // Guard: no backend configured — prevent silent VIP grant without payment
    const showCheckoutUnavailable = () => {
      setShowUpgradeModal(false);
      setNotif({ title:"VIP checkout is almost ready.", body:"Please try again soon.", icon:"✦", color:C.gold });
    };
    if (!API_URL) { showCheckoutUnavailable(); return; }
    let data;
    try {
      const res = await fetch(`${API_URL}/api/subscriptions/checkout`, {
        method:"POST",
        headers:{ 'Content-Type':'application/json', ...(api._token ? { Authorization:`Bearer ${api._token}` } : {}) },
        body:JSON.stringify({
          plan: selectedPlan,
          userId: user?.id,
          email: user?.email,
          successUrl: `${window.location.origin}?checkout=success`,
          cancelUrl: `${window.location.origin}?checkout=cancel`,
        }),
      });
      data = await res.json().catch(()=>({}));
      if (!res.ok && !data?.url) { console.warn('[Checkout] Backend error:', res.status, data); }
      if (res.status === 409 && data?.soldOut) {
        setShowUpgradeModal(false);
        setNotif({
          title:"Founder Pass Sold Out ✦",
          body:"The first 500 Backstagers claimed this drop. Monthly and Annual VIP are still available.",
          icon:"✦",
          color:C.gold,
        });
        { const p=getDeliveryPrefs(user); deliverNotification({ notif:{ type:"payment", icon:"✦", title:"Founder Pass Sold Out ✦", body:"The first 500 Backstagers claimed this drop. Monthly and Annual VIP are still available.", color:C.gold }, pushEnabled:p.pushEnabled, emailBackup:p.emailBackup, priority:'high' }); }
        return;
      }
    } catch {
      showCheckoutUnavailable();
      return;
    }
    if (data?.url) { window.location.href = data.url; return; }
    showCheckoutUnavailable();
  };

  const openUpgrade = () => setShowUpgradeModal(true);
  const showNotif   = (n) => setNotif(n);

  // ── SIGN OUT ───────────────────────────────────────────────────────────────
  const handleSignOut = async () => {
    ls.del('backstage_session');
    ls.del('backstage_is_vip');
    ls.del('backstage_pending_uid');
    if(_supabase) await _supabase.auth.signOut();
    setUser(null);
    setIsVip(false);
    setAppState("auth");
    setTab("community");
  };

  const go = (dest) => {
    // "+" shortcut on the Your Pass story bubble — jump straight into the Pass
    // composer instead of just opening the Backstage Passes browsing page.
    if(dest==="passes_create"){ ls.set("backstage_open_pass_composer", true); dest = "passes"; }
    const FULL_MODALS = ["concertprep","myshows","scrapbook","afterglow","friends","chats","qr","safety","events","concertday","timeline","tickets","nearby","trust","games","creator","backup","fanidentity","valuetracks","fanprojects","assistant","invite","contentgen","fanmap","livefeed","budget","capsule","passes","notifications"];
    if(FULL_MODALS.includes(dest)){
      // Push a new history entry so the browser back button can close this modal
      window.history.pushState({ bsLevel:1, modal:dest }, '');
      setModal(dest);
      return;
    }
    if(dest==="collect"||dest==="shelf"){ setTab("collect"); setModal(null); return; }
    if(dest==="fanverse"){ setTab("community"); setModal(null); return; }
    if(dest==="studio"){ ls.set("backstage_open_studio",true); setTab("profile"); setModal(null); return; }
    if(dest==="tools"){ setTab("fanverse"); setModal(null); return; }
    // Deep-link to specific concert sub-tabs
    if(dest==="concerts_meetups"){ ls.set("backstage_concerts_view","meetups"); setTab("concerts"); setModal(null); return; }
    if(dest==="concerts_parties"){ ls.set("backstage_concerts_view","parties"); setTab("concerts"); setModal(null); return; }
    if(dest==="concerts_fans"){    ls.set("backstage_concerts_view","fans");    setTab("concerts"); setModal(null); return; }
    if(dest==="concerts_create_meetup"){ ls.set("backstage_concerts_view","meetups"); ls.set("backstage_open_create_meetup",true); setTab("concerts"); setModal(null); return; }
    if(dest==="signout"){ handleSignOut(); return; }
    const tabs = ["home","concerts","community","collect","fanverse","explore","profile","feed"];
    if(tabs.includes(dest)){
      if(dest!=="community") window.history.pushState({ bsLevel:1, tab:dest }, '');
      setTab(dest); setModal(null); return;
    }
    if(["kdramas","chants","eras"].includes(dest)){ setTab("fanverse"); setModal(null); return; }
    setTab(dest);
  };

  // Auto-prompt disabled — push is opt-in via Settings only.
  // showNotifPrompt state + UI kept for future opt-in flows; never triggered automatically.

  // Handle push notification deep-links, OAuth callbacks, and Stripe checkout returns
  useEffect(()=>{
    const params = new URLSearchParams(window.location.search);

    const referralParam = params.get('ref');
    if (referralParam) {
      ls.set('backstage_pending_referral_code', referralParam);
    }

    // Stripe checkout success return
    // ALWAYS store in localStorage first so it survives a login if the session
    // was lost during the Stripe redirect (common on Safari / PWA mode).
    const checkoutParam = params.get('checkout');
    if (checkoutParam === 'success') {
      window.history.replaceState({}, '', window.location.pathname);
      ls.set('backstage_pending_vip_checkout', true);
      if (appState !== 'main') {
        // Session is gone — tell the user to sign back in; activation runs after login
        setNotif({ title:"Payment received ✦", body:"Sign back in to activate your Founder Pass.", icon:"✦", color:C.gold });
      }
    }

    // Process a pending VIP checkout the moment we reach main state
    // (runs on first load if session was intact, OR after the user re-authenticates)
    if (appState === 'main' && ls.get('backstage_pending_vip_checkout')) {
      ls.del('backstage_pending_vip_checkout');

      const activateVip = (attempt = 1) => {
        api.get('/api/subscriptions/status').then(d => {
          if (d?.is_vip) {
            setIsVip(true);
            setCachedVip(user, true);
            setUser(u => {
              if (!u) return u;
              return { ...u, is_vip: true, vip_source: d.vip_source || 'stripe' };
            });
            const sess = ls.get('backstage_session');
            if (sess?.user) ls.set('backstage_session', {
              ...sess,
              user: { ...sess.user, is_vip: true, vip_source: d.vip_source || 'stripe' },
            });
            setShowVipCelebration(true);
          } else if (attempt < 4) {
            // Webhook may not have fired yet — retry up to 3 more times
            setTimeout(() => activateVip(attempt + 1), 4000 * attempt);
          } else {
            setNotif({ title:"Founder Pass received ✦", body:"Access is activating — reopen Backstage in a moment to complete.", icon:"✦", color:C.gold });
            { const p=getDeliveryPrefs(user); deliverNotification({ notif:{ type:"vip", icon:"✦", title:"Founder Pass received ✦", body:"Access is activating — reopen Backstage to complete.", color:C.gold }, pushEnabled:p.pushEnabled, emailBackup:p.emailBackup, priority:'critical' }); }
          }
        }).catch(() => {
          setNotif({ title:"Payment received ✦", body:"Sign in to finish activating your Founder Pass.", icon:"✦", color:C.gold });
          { const p=getDeliveryPrefs(user); deliverNotification({ notif:{ type:"vip", icon:"✦", title:"Payment received ✦", body:"Sign in to finish activating your Founder Pass.", color:C.gold }, pushEnabled:p.pushEnabled, emailBackup:p.emailBackup, priority:'critical' }); }
        });
      };
      activateVip();
    }

    const notifDest = params.get('notif');
    if (notifDest && appState === 'main') {
      window.history.replaceState({}, '', window.location.pathname);
      go(notifDest);
    }
    // Spotify OAuth return: ?music=spotify_connected
    const musicParam = params.get('music');
    if (musicParam === 'spotify_connected' && appState === 'main') {
      window.history.replaceState({}, '', window.location.pathname);
      ls.set('backstage_music_connected', 'spotify');
      setNotif({ title:"Spotify Connected 🎵", body:"Your Now Playing will sync automatically.", icon:"🎵", color:C.mint });
    }
    // PWA shortcut: ?tab=collect|concerts|community
    const tabParam = params.get('tab');
    if (tabParam && appState === 'main') {
      window.history.replaceState({}, '', window.location.pathname);
      go(tabParam);
    }
    const onSwMessage = (event) => {
      if (event.data?.type === 'NOTIF_CLICK' && appState === 'main') {
        const dest = event.data.targetModal || event.data.targetTab;
        if (dest) go(dest);
      }
    };
    navigator.serviceWorker?.addEventListener('message', onSwMessage);
    return () => navigator.serviceWorker?.removeEventListener('message', onSwMessage);
  },[appState]);

  useEffect(() => {
    if (!auth.user?.id || !auth.tokenReady) return;
    const code = ls.get('backstage_pending_referral_code');
    if (!code) return;
    api.post('/api/referrals/claim', { code }).then(() => {
      ls.del('backstage_pending_referral_code');
    }).catch(() => {});
  }, [auth.user?.id, auth.tokenReady]);

  useEffect(()=>{
    if(appState!=="main") return;
    const shows = ls.get("backstage_myshows",[]);
    const recent = shows.filter(s=>{ try { return (Date.now()-new Date(s.createdAt).getTime()) < 48*60*60*1000; } catch { return false; } });
    if(recent.length && !ls.get(`backstage_afterglow_nudged_${recent[0]?.id}`)){
      setTimeout(()=>{
        setNotif({ title:`How are you feeling after ${recent[0]?.name}?`, body:"Don't forget your Afterglow ✨", icon:"✨", color:C.accent });
        ls.set(`backstage_afterglow_nudged_${recent[0]?.id}`, true);
      }, 8000);
    }
  },[appState]);

  const NAV = [
    {id:"community", icon:"community", label:"Fanverse"},
    {id:"explore",   icon:"explore",   label:"Explore"},
    {id:"collect",   icon:"shelf",     label:"My World"},
    {id:"fanverse",  icon:"fanverse",  label:"Tools"},
    {id:"profile",   icon:"profile",   label:"My Stage"},
  ];

  const ToolModalWrapper = ({ title, children }) => (
    <ModalWrapper>
      <div style={{ padding:"16px 20px 0",flexShrink:0,display:"flex",alignItems:"center",gap:10 }}>
        <button onClick={()=>setModal(null)} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <h2 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:19 }}>{title}</h2>
      </div>
      <Screen>{children}</Screen>
    </ModalWrapper>
  );

  // /capsule path: show landing page for signed-out fans
  if (showCapsuleLanding) {
    return <CapsuleLandingPage
      onJoin={()=>{ setShowCapsuleLanding(false); setShowCapsulePreview(true); }}
      onExplore={()=>{ setShowCapsuleLanding(false); setShowCapsulePreview(true); }}
    />;
  }

  // /capsule preview: signed-out fan browses the capsule; "Add Moment" triggers auth gate
  if (showCapsulePreview) {
    return (
      <>
        <style>{getCSS()}</style>
        <div className="cosmic-bg app-shell" style={{ background:`linear-gradient(160deg,${C.cosmic} 0%,${C.bg} 40%,${C.surfaceMid} 100%)`,display:"flex",flexDirection:"column",overflow:"hidden" }}>
          <ConcertCapsule
            concert={MOCK_CONCERTS[0]}
            onBack={()=>setShowCapsulePreview(false)}
            user={null}
            isSignedOut={true}
            fromCapsulePath={true}
            onSignupRequired={()=>setShowCapsulePreview(false)}
            isVip={false}
            onUpgrade={()=>{}}
          />
        </div>
      </>
    );
  }

  return(
    <ThemeContext.Provider value={{ themeMode, setThemeMode }}>
    <>
      <style>{getCSS()}</style>
      <div className="cosmic-bg app-shell" style={{ background:`linear-gradient(160deg,${C.cosmic} 0%,${C.bg} 40%,${C.surfaceMid} 100%)`, display:"flex", flexDirection:"column", overflow:"hidden" }}>

        {/* OFFLINE BANNER */}
        <OfflineReadyBanner />

        {/* IN-APP NOTIF */}
        {notif&&<NotifBanner notif={notif} onDismiss={()=>setNotif(null)} />}

        {/* VIP MODAL */}
        {showUpgradeModal&&<UpgradeModal onClose={()=>setShowUpgradeModal(false)} onUpgrade={handleUpgrade} />}

        {/* VIP CELEBRATION → auto-advances to tour */}
        {showVipCelebration&&<VipCelebrationScreen vipSource={user?.vip_source} onDone={()=>{ setShowVipCelebration(false); setShowVipTour(true); }} />}

        {/* VIP TUTORIAL */}
        {showVipTour&&<VipTutorialModal
          onNavigate={(dest)=>go(dest)}
          onDone={()=>{ setShowVipTour(false); setNotif({ title:"Welcome to Backstage VIP ✦", body:"Your full fan era starts now.", icon:"✦", color:C.gold }); }}
        />}

        {/* SMART NOTIFS */}
        {showSmartNotifs&&<SmartNotifs onClose={()=>setShowSmartNotifs(false)} />}

        {/* NOTIF PROMPT */}
        {showNotifPrompt&&appState==="main"&&(
          <div style={{ position:"absolute",top:0,left:0,right:0,bottom:0,zIndex:500,background:"rgba(6,6,15,0.92)",display:"flex",alignItems:"flex-end",animation:"in .25s ease" }}>
            <div style={{ background:`linear-gradient(160deg,${C.surfaceMid},${C.cosmic})`,borderRadius:"28px 28px 0 0",padding:"24px 24px 28px",width:"100%",animation:"slideUp .3s ease",border:`1.5px solid ${C.borderHi}`,position:"relative",overflow:"hidden" }}>
              {/* Cosmic sparkle bg */}
              {[{t:"10%",l:"80%",s:12,d:"0s"},{t:"60%",l:"90%",s:8,d:"1s"},{t:"80%",l:"10%",s:7,d:"0.5s"}].map((sp,i)=>(
                <div key={i} style={{ position:"absolute",top:sp.t,left:sp.l,fontSize:sp.s,opacity:0.35,animation:`sparkleFloat 3s ease-in-out infinite`,animationDelay:sp.d,pointerEvents:"none",color:C.lavender }}>✦</div>
              ))}
              <div style={{ position:"absolute",top:0,left:0,right:0,height:1,background:`linear-gradient(90deg,transparent,${C.lavender}44,transparent)` }} />
              <div style={{ width:36,height:4,borderRadius:99,background:C.border,margin:"0 auto 20px" }} />
              {/* Icon */}
              <div style={{ width:56,height:56,borderRadius:18,background:`linear-gradient(135deg,${C.accent}30,${C.berry}20)`,border:`1.5px solid ${C.accent}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:26,marginBottom:16,boxShadow:`0 8px 24px ${C.accent}18` }}>🔔</div>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:20,marginBottom:6,background:`linear-gradient(135deg,${C.lavender},${C.blush})`,WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent" }}>Stay in the loop</p>
              <p style={{ fontSize:12.5,color:C.textMid,lineHeight:1.7,marginBottom:18 }}>Concert reminders, trade matches, meetup updates, and fan chants — all in one place.</p>
              <div style={{ background:`linear-gradient(140deg,${C.surface},${C.surfaceHi})`,borderRadius:16,padding:14,marginBottom:18,border:`1px solid ${C.borderHi}` }}>
                {[["🎤","Concert day reminders"],[  "🃏","Trade matches & updates"],["🎁","Meetup & freebie alerts"],["✨","Afterglow prompts"]].map(([icon,label],i)=>(
                  <div key={i} style={{ display:"flex",alignItems:"center",gap:12,paddingBottom:i<3?10:0,borderBottom:i<3?`1px solid ${C.border}`:"none",paddingTop:i>0?10:0 }}>
                    <div style={{ width:30,height:30,borderRadius:9,background:`${C.accent}18`,border:`1px solid ${C.accent}28`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,flexShrink:0 }}>{icon}</div>
                    <p style={{ fontSize:12.5,color:C.text }}>{label}</p>
                  </div>
                ))}
              </div>
              <Btn onClick={async()=>{ const pushUserKey=user?.id||user?.email||"anon"; ls.set(`backstage_push_prompted_${pushUserKey}`,true); const t=await requestNotificationPermission(user?.id||user?.name||"user"); if(t){ ls.set(`backstage_push_enabled_${pushUserKey}`,true); ls.set(`backstage_push_token_${pushUserKey}`,t); setNotif({title:"Notifications enabled! 🔔",body:"You'll get concert alerts, trade updates, and more.",icon:"🔔",color:C.accent}); }else{ ls.set(`backstage_push_enabled_${pushUserKey}`,false); } setShowNotifPrompt(false); }}>Enable Notifications</Btn>
              <div style={{ height:10 }} />
              <Btn ghost color={C.textMid} onClick={()=>{ const pushUserKey=user?.id||user?.email||"anon"; ls.set(`backstage_push_prompted_${pushUserKey}`,true); ls.set("backstage_notif_prompt_dismissed",true); setShowNotifPrompt(false); }}>Not now</Btn>
            </div>
          </div>
        )}

        {/* ── ALL MODALS ── */}
        {modal==="concertprep"&&<ToolModalWrapper title="Concert Prep Guide 📋"><ConcertPrep /></ToolModalWrapper>}
        {modal==="myshows"&&<ModalWrapper><MyShowsPage onBack={()=>setModal(null)} isVip={isVip} onUpgrade={openUpgrade} go={go} /></ModalWrapper>}
        {modal==="scrapbook"&&<ModalWrapper><ScrapbookTab isVip={isVip} onUpgrade={openUpgrade} onBack={()=>setModal(null)} /></ModalWrapper>}
        {modal==="friends"&&<ModalWrapper><FriendsPage onBack={()=>setModal(null)} onNotif={showNotif} go={go} onViewProfile={(fan)=>setPublicProfileFan({...fan,fromDM:false})} /></ModalWrapper>}
        {modal==="fanmap"&&<ModalWrapper><FanverseMap onBack={()=>setModal(null)} /></ModalWrapper>}
        {modal==="chats"&&<ModalWrapper><DirectMessages onBack={()=>setModal(null)} user={user} onViewProfile={(fan)=>setPublicProfileFan({...fan,fromDM:true})} /></ModalWrapper>}
        {modal==="qr"&&<ModalWrapper><QRPage onBack={()=>setModal(null)} user={user} onNotif={showNotif} /></ModalWrapper>}
        {modal==="safety"&&<ModalWrapper><SafetyCenter onBack={()=>setModal(null)} /></ModalWrapper>}
        {modal==="events"&&<ModalWrapper><EventDiscovery onBack={()=>setModal(null)} go={go} /></ModalWrapper>}
        {modal==="concertday"&&<ModalWrapper><ConcertDayMode concert={MOCK_CONCERTS[0]} onBack={()=>setModal(null)} go={go} isVip={isVip} onUpgrade={openUpgrade} /></ModalWrapper>}
        {modal==="timeline"&&<ModalWrapper><EventTimeline concert={MOCK_CONCERTS[0]} onBack={()=>setModal(null)} /></ModalWrapper>}
        {modal==="tickets"&&<ModalWrapper><TicketWallet onBack={()=>setModal(null)} /></ModalWrapper>}
        {modal==="nearby"&&<ModalWrapper><MicroMoments onBack={()=>setModal(null)} /></ModalWrapper>}
        {modal==="trust"&&<ModalWrapper><TrustProfile onBack={()=>setModal(null)} onNotif={showNotif} /></ModalWrapper>}
        {modal==="games"&&<ModalWrapper><MiniGames onBack={()=>setModal(null)} /></ModalWrapper>}
        {modal==="creator"&&<ModalWrapper><CreatorMode onBack={()=>setModal(null)} /></ModalWrapper>}
        {modal==="backup"&&<ModalWrapper><BackupExport onBack={()=>setModal(null)} isVip={isVip} onUpgrade={openUpgrade} /></ModalWrapper>}
        {modal==="fanidentity"&&<ModalWrapper><FanIdentity onBack={()=>setModal(null)} /></ModalWrapper>}
        {modal==="valuetracks"&&<ModalWrapper><ValueTracker onBack={()=>setModal(null)} isVip={isVip} onUpgrade={openUpgrade} /></ModalWrapper>}
        {modal==="budget"&&<ModalWrapper><BudgetTracker onBack={()=>setModal(null)} /></ModalWrapper>}
        {modal==="fanprojects"&&<ModalWrapper><FanProjects onBack={()=>setModal(null)} /></ModalWrapper>}
        {modal==="assistant"&&<ModalWrapper><AIAssistant onBack={()=>setModal(null)} user={user} go={go} /></ModalWrapper>}
        {modal==="livefeed"&&<ModalWrapper><LiveFeedTab user={user} go={go} onBack={()=>setModal(null)} /></ModalWrapper>}
        {/* PHASE 5 MODALS */}
        {modal==="notifications"&&<ModalWrapper><StandaloneNotifCenter
          user={user}
          onBack={()=>setModal(null)}
          onNavigate={(dest)=>{
            // Close notifications, then open the target modal or tab
            setModal(null);
            if (dest.modal) setTimeout(()=>setModal(dest.modal), 60);
            else if (dest.tab) { setTimeout(()=>setTab(dest.tab), 60); }
          }}
        /></ModalWrapper>}
        {modal==="invite"&&<ModalWrapper><InvitePage onBack={()=>setModal(null)} user={user} onNotif={showNotif} isVip={isVip} onUpgrade={openUpgrade} go={go} onViewProfile={setFullProfileFan} /></ModalWrapper>}
        {modal==="contentgen"&&<ModalWrapper><ContentGenerator onBack={()=>setModal(null)} user={user} go={go} onNotif={showNotif} /></ModalWrapper>}
        {modal==="capsule"&&<ModalWrapper><ConcertCapsule concert={MOCK_CONCERTS[0]} onBack={()=>setModal(null)} user={user} isVip={isVip} onUpgrade={openUpgrade} /></ModalWrapper>}
        {modal==="passes"&&<ModalWrapper><BackstagePasses onBack={()=>setModal(null)} user={user} /></ModalWrapper>}

        {modal==="collectmodal"&&<ModalWrapper><div style={{ height:"100%",display:"flex",flexDirection:"column",overflow:"hidden" }}><div style={{ padding:"16px 20px",display:"flex",gap:10,alignItems:"center",flexShrink:0 }}><button onClick={()=>setModal(null)} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button><h2 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:19 }}>My Collection 🃏</h2></div><Screen style={{ padding:"0 20px calc(120px + env(safe-area-inset-bottom))" }}><CollectTab cards={cards} setCards={setCards} isVip={isVip} onUpgrade={openUpgrade} /></Screen></div></ModalWrapper>}

        {/* ── MAIN SCREENS ── */}
        <div style={{ flex:1, overflow:"hidden", position:"relative", paddingBottom:"calc(62px + max(env(safe-area-inset-bottom), 10px))" }}>
          {auth.passwordRecovery&&<SetNewPasswordScreen />}
          {!auth.passwordRecovery&&(appState==="auth"||appState==="onboarding")&&<Onboarding onDone={data=>{
            if (!data) { console.error('[App] onDone called with null — skipping'); return; }
            const profile = normalizeProfile(data);
            setUser(profile);
            ls.set("backstage_session", { user: profile });
            if (profile.id) ls.set(`backstage_profile_${profile.id}`, profile);
            if (!canEnterApp(profile)) {
              setAppState("onboarding");
              return;
            }
            markOnboardingComplete(profile);
            setAppState("main");
            // Restore capsule context if user came from QR/capsule link
            const capsuleCtx = ls.get("backstage_capsule_context");
            if (fromCapsule || capsuleCtx) setModal("capsule");
          }} />}
          {appState==="main"&&!modal&&(
            <>
              {/* effectiveIsVip: truthy if the backend-synced state OR any local cache confirms VIP.
                  Prevents the upgrade banner from flashing for VIP users on cold Render starts. */}
              {(()=>{
                const effectiveIsVip = isVip || hasVipEntitlement(user) || getCachedVip(user);
                return (
                  <>
              {tab==="concerts"&&<ConcertsPage go={go} isVip={effectiveIsVip} onUpgrade={openUpgrade} user={user} />}
              {tab==="community"&&<FanverseTab go={go} user={user} isVip={effectiveIsVip} onUpgrade={openUpgrade} onViewProfile={setFullProfileFan} />}
              {tab==="explore"&&<ExploreTab user={user} go={go} onViewProfile={setFullProfileFan} />}
              {tab==="collect"&&<LibraryTab cards={cards} setCards={setCards} isVip={effectiveIsVip} onUpgrade={openUpgrade} go={go} user={user} weather={weatherData} />}
              {tab==="fanverse"&&<ToolsTab user={user} weather={weatherData} isVip={effectiveIsVip} onUpgrade={openUpgrade} go={go} />}
              {tab==="profile"&&<ProfileTab user={user} cards={cards} go={go} isVip={effectiveIsVip} onUpgrade={openUpgrade} onReplayTour={()=>setShowVipTour(true)} onAccountRefresh={handleAccountRefresh} onViewProfile={setFullProfileFan} />}
                  </>
                );
              })()}
              {/* Ask Backstage AI — hidden on profile (has its own Studio/Preview actions) and
                  community (Fanverse renders its own combined Messages+AI dock instead) */}
              {tab!=="profile"&&tab!=="collect"&&tab!=="community"&&<AskBackstageButton go={go} />}
              {/* Notification Bell — floating, hidden on profile (section nav), collect (own + Add button) */}
              {tab!=="profile"&&tab!=="collect"&&<NotificationBell onOpen={()=>setModal("notifications")} />}
            </>
          )}
        </div>

        {/* BOTTOM NAV */}
        {appState==="main"&&!modal&&(
          <div className="bs-bottom-nav" style={{ position:"absolute",left:0,right:0,bottom:0,display:"flex",minHeight:62,background:C.navBg,borderTop:`1px solid ${C.borderHi}`,paddingBottom:"max(env(safe-area-inset-bottom), 10px)",backdropFilter:"blur(24px)",boxShadow:"0 -1px 0 rgba(184,162,255,0.06)",zIndex:100 }}>
            {NAV.map(n=>{
              const active = tab===n.id;
              const NAV_ICONS = {
                home: <svg width="22" height="22" viewBox="0 0 24 24" fill="none"><path d="M7.15 19.55V8.45C7.15 7.88 7.43 7.35 7.9 7.03L11.05 4.9C11.62 4.52 12.38 4.52 12.95 4.9L16.1 7.03C16.57 7.35 16.85 7.88 16.85 8.45V19.55" stroke={active?"url(#navGrad)":C.textDim} strokeWidth="1.45" strokeLinecap="round" strokeLinejoin="round"/><path d="M5.25 19.55H18.75" stroke={active?"url(#navGrad)":C.textDim} strokeWidth="1.45" strokeLinecap="round"/><path d="M9.65 11.2C9.18 10.55 9.28 9.65 9.9 9.22C10.48 8.82 11.25 9.02 11.75 9.58L12 9.85L12.25 9.58C12.75 9.02 13.52 8.82 14.1 9.22C14.72 9.65 14.82 10.55 14.35 11.2C14.05 11.6 13.65 11.98 13.18 12.4L12 13.45L10.82 12.4C10.35 11.98 9.95 11.6 9.65 11.2Z" fill={active?"url(#navGrad)":C.textDim}/><path d="M12 15.15V16.85" stroke={active?"url(#navGrad)":C.textDim} strokeWidth="1.25" strokeLinecap="round" opacity="0.45"/><path d="M19.25 5.2L19.72 6.08L20.6 6.55L19.72 7.02L19.25 7.9L18.78 7.02L17.9 6.55L18.78 6.08L19.25 5.2Z" fill={active?"url(#navGrad)":C.textDim} opacity={active?0.72:0.45}/><defs><linearGradient id="navGrad" x1="0" y1="0" x2="24" y2="24"><stop stopColor={C.accent}/><stop offset="1" stopColor={C.pink}/></linearGradient></defs></svg>,
                concerts: <svg width="22" height="22" viewBox="0 0 24 24" fill="none"><path d="M12 2C12 2 7 6 7 11C7 13.76 9.24 16 12 16C14.76 16 17 13.76 17 11C17 6 12 2 12 2Z" fill={active?"url(#navG2)":"none"} stroke={active?"url(#navG2)":C.textDim} strokeWidth="1.8"/><path d="M8 20H16M12 16V20" stroke={active?"url(#navG2)":C.textDim} strokeWidth="1.8" strokeLinecap="round"/><defs><linearGradient id="navG2" x1="0" y1="0" x2="24" y2="24"><stop stopColor={C.accent}/><stop offset="1" stopColor={C.pink}/></linearGradient></defs></svg>,
                community: <svg width="22" height="22" viewBox="0 0 24 24" fill="none"><path d="M12 3.75C8.75 3.75 6.15 6.28 6.15 9.48C6.15 13.55 12 20.25 12 20.25C12 20.25 17.85 13.55 17.85 9.48C17.85 6.28 15.25 3.75 12 3.75Z" stroke={active?"url(#navG3)":C.textDim} strokeWidth="1.55" strokeLinejoin="round" fill={active?"url(#navG3Soft)":"none"}/><path d="M12 6.9L12.9 9.1L15.1 10L12.9 10.9L12 13.1L11.1 10.9L8.9 10L11.1 9.1L12 6.9Z" fill={active?"url(#navG3)":C.textDim}/><path d="M18.8 14.8C19.95 15.18 20.65 15.72 20.65 16.32C20.65 17.68 16.78 18.78 12 18.78C7.22 18.78 3.35 17.68 3.35 16.32C3.35 15.72 4.05 15.18 5.2 14.8" stroke={active?"url(#navG3)":C.textDim} strokeWidth="1.25" strokeLinecap="round" opacity="0.42"/><path d="M19.85 5.1L20.32 5.98L21.2 6.45L20.32 6.92L19.85 7.8L19.38 6.92L18.5 6.45L19.38 5.98L19.85 5.1Z" fill={active?"url(#navG3)":C.textDim} opacity={active?0.8:0.5}/><defs><linearGradient id="navG3" x1="0" y1="0" x2="24" y2="24"><stop stopColor={C.accent}/><stop offset="1" stopColor={C.pink}/></linearGradient><linearGradient id="navG3Soft" x1="0" y1="0" x2="24" y2="24"><stop stopColor={C.accent} stopOpacity="0.16"/><stop offset="1" stopColor={C.pink} stopOpacity="0.06"/></linearGradient></defs></svg>,
                explore: <svg width="22" height="22" viewBox="0 0 24 24" fill="none"><circle cx="12" cy="12" r="7.75" stroke={active?"url(#navG7)":C.textDim} strokeWidth="1.5"/><path d="M15.35 8.65L13.15 13.15L8.65 15.35L10.85 10.85L15.35 8.65Z" fill={active?"url(#navG7)":C.textDim} stroke={active?"url(#navG7)":C.textDim} strokeWidth="0.6" strokeLinejoin="round"/><path d="M18.9 3.25L19.3 4L20.05 4.4L19.3 4.8L18.9 5.55L18.5 4.8L17.75 4.4L18.5 4L18.9 3.25Z" fill={active?"url(#navG7)":C.textDim} opacity={active?0.78:0.45}/><defs><linearGradient id="navG7" x1="0" y1="0" x2="24" y2="24"><stop stopColor={C.accent}/><stop offset="1" stopColor={C.berry}/></linearGradient></defs></svg>,
                shelf: <BackstageBNavIcon active={active} />,
                fanverse: <svg width="22" height="22" viewBox="0 0 24 24" fill="none"><path d="M8.05 4.75H15.95C17.78 4.75 19.25 6.22 19.25 8.05V15.95C19.25 17.78 17.78 19.25 15.95 19.25H8.05C6.22 19.25 4.75 17.78 4.75 15.95V8.05C4.75 6.22 6.22 4.75 8.05 4.75Z" stroke={active?"url(#navG6)":C.textDim} strokeWidth="1.45" strokeLinejoin="round" fill={active?"url(#navG6Soft)":"none"}/><path d="M12 7.7L12.92 10.12L15.35 11.05L12.92 11.98L12 14.4L11.08 11.98L8.65 11.05L11.08 10.12L12 7.7Z" fill={active?"url(#navG6)":C.textDim}/><path d="M8.7 15.6H15.3" stroke={active?"url(#navG6)":C.textDim} strokeWidth="1.25" strokeLinecap="round" opacity="0.5"/><path d="M18.9 3.25L19.3 4L20.05 4.4L19.3 4.8L18.9 5.55L18.5 4.8L17.75 4.4L18.5 4L18.9 3.25Z" fill={active?"url(#navG6)":C.textDim} opacity={active?0.78:0.45}/><defs><linearGradient id="navG6" x1="0" y1="0" x2="24" y2="24"><stop stopColor={C.accent}/><stop offset="1" stopColor={C.mint}/></linearGradient><linearGradient id="navG6Soft" x1="0" y1="0" x2="24" y2="24"><stop stopColor={C.accent} stopOpacity="0.18"/><stop offset="1" stopColor={C.mint} stopOpacity="0.08"/></linearGradient></defs></svg>,
                profile: <svg width="22" height="22" viewBox="0 0 24 24" fill="none"><path d="M5.25 12.15C5.25 8.42 8.27 5.4 12 5.4C15.73 5.4 18.75 8.42 18.75 12.15C18.75 15.88 15.73 18.9 12 18.9C8.27 18.9 5.25 15.88 5.25 12.15Z" stroke={active?"url(#navG5)":C.textDim} strokeWidth="1.45"/><path d="M8.25 11.2C7.72 10.3 7.9 9.25 8.65 8.72C9.38 8.2 10.35 8.42 11.05 9.15L12 10.15L12.95 9.15C13.65 8.42 14.62 8.2 15.35 8.72C16.1 9.25 16.28 10.3 15.75 11.2C15.42 11.78 14.88 12.32 14.25 12.9L12 14.95L9.75 12.9C9.12 12.32 8.58 11.78 8.25 11.2Z" fill={active?"url(#navG5)":C.textDim}/><path d="M12 2.9V4.1M12 20.2V21.1M2.9 12.15H4.1M19.9 12.15H21.1" stroke={active?"url(#navG5)":C.textDim} strokeWidth="1.25" strokeLinecap="round" opacity="0.48"/><path d="M17.95 4.25L18.48 5.25L19.48 5.78L18.48 6.31L17.95 7.31L17.42 6.31L16.42 5.78L17.42 5.25L17.95 4.25Z" fill={active?"url(#navG5)":C.textDim} opacity={active?0.78:0.45}/><defs><linearGradient id="navG5" x1="0" y1="0" x2="24" y2="24"><stop stopColor={C.accent}/><stop offset="1" stopColor={C.pink}/></linearGradient></defs></svg>,
              };
              return(
                <button key={n.id} onClick={()=>{ if(n.id==="fanverse" && tab==="fanverse"){ window.dispatchEvent(new Event("bs:fanverse-reset")); } setTab(n.id); }} style={{ flex:1, background:"none", border:"none", padding:"10px 2px 8px", display:"flex", flexDirection:"column", alignItems:"center", gap:3, position:"relative", transition:"opacity .15s" }}>
                  {/* Active top accent line */}
                  {active&&<div style={{ position:"absolute", top:0, left:"50%", transform:"translateX(-50%)", width:32, height:2, background:`linear-gradient(90deg,${C.accent},${C.pink})`, borderRadius:99, boxShadow:`0 0 8px ${C.accent}80` }} />}
                  {/* Active ambient glow */}
                  {active&&<div style={{ position:"absolute", top:-2, left:"50%", transform:"translateX(-50%)", width:48, height:28, background:`radial-gradient(ellipse,${C.accent}1c,transparent 70%)`, pointerEvents:"none", animation:"ambientGlow 3s ease-in-out infinite" }} />}
                  <div style={{ width:22, height:22, display:"flex", alignItems:"center", justifyContent:"center", position:"relative" }}>
                    {NAV_ICONS[n.icon]}
                    {/* DM unread badge on Profile tab */}
                    {n.id==="profile"&&(()=>{const u=ls.get("backstage_dms",[]).reduce((s,c)=>s+c.unread,0); return u>0?<div style={{ position:"absolute",top:-3,right:-3,width:14,height:14,borderRadius:"50%",background:C.rose,display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontFamily:"'Epilogue',sans-serif",fontWeight:800,color:C.bg }}>{u}</div>:null; })()}
                  </div>
                  <span style={{ fontSize:8, fontFamily:"'Epilogue',sans-serif", fontWeight:active?800:500, color:active?C.accent:C.textMid, letterSpacing:"0.04em", transition:"color .18s" }}>{n.label}</span>
                </button>
              );
            })}
          </div>
        )}

      {/* ── COMPACT PROFILE CARD — step 1, z:600 */}
      {publicProfileFan&&!fullProfileFan&&(
        <div style={{ position:"absolute",inset:0,zIndex:600,display:"flex",flexDirection:"column",paddingTop:"calc(env(safe-area-inset-top,0px) + 10px)" }}>
          <PublicProfilePreview
            fan={publicProfileFan}
            onBack={()=>setPublicProfileFan(null)}
            onBackToMessage={()=>setPublicProfileFan(null)}
            onViewFullProfile={(f)=>setFullProfileFan(f)}
            onMessage={(f)=>{ ls.set("backstage_dm_target",f); setPublicProfileFan(null); setModal("chats"); }}
            go={(dest)=>{ setPublicProfileFan(null); go(dest); }}
          />
        </div>
      )}
      {/* ── FULL RICH PROFILE — z:650; direct from any fan tap or step 2 from DM compact card */}
      {fullProfileFan&&(
        <div style={{ position:"absolute",inset:0,zIndex:650,display:"flex",flexDirection:"column",background:C.bg,overflow:"hidden",paddingTop:"calc(env(safe-area-inset-top,0px) + 10px)" }}>
          <PublicProfileFull
            fan={fullProfileFan}
            onBack={()=>setFullProfileFan(null)}
            onBackToMessage={()=>{ setFullProfileFan(null); setPublicProfileFan(null); }}
            onMessage={(f)=>{ ls.set("backstage_dm_target",f); setFullProfileFan(null); setPublicProfileFan(null); setModal("chats"); }}
            go={(dest)=>{ setFullProfileFan(null); setPublicProfileFan(null); go(dest); }}
          />
        </div>
      )}
      </div>{/* close app-shell */}
    </>
    </ThemeContext.Provider>
  );
}
